import org.apache.spark.sql._
import org.apache.spark.sql.types._
import org.apache.spark.sql.functions._
import org.apache.spark.ml.feature._
import org.apache.spark.ml.regression._
import org.apache.spark.ml.evaluation._
import org.apache.spark.ml.Pipeline
import ml.dmlc.xgboost4j.scala.spark.XGBoostRegressor
import java.io.{File, PrintWriter} object AcceleratedSparkPipeline { def main(args: Array[String]): Unit = { // STEP 1: Initialize Spark Session with GPU configuration val spark = SparkSession.builder() .appName("GPU-Accelerated Spark Pipeline") .master("local[*]") .config("spark.plugins", "com.nvidia.spark.SQLPlugin") .config("spark.sql.adaptive.enabled", "true") .config("spark.sql.adaptive.coalescePartitions.enabled", "true") .config("spark.rapids.sql.enabled", "true") .config("spark.rapids.memory.gpu.pooling.enabled", "true") .getOrCreate() // STEP 2: Import Core Libraries (already imported above) import spark.implicits._ println("=== GPU-Accelerated Spark Pipeline Started ===") // Generate synthetic datasets generateSyntheticData(spark) // Run taxi data analysis runTaxiAnalysis(spark) // Run housing ML pipeline runHousingMLPipeline(spark) spark.stop() println("=== Pipeline Completed ===") } def generateSyntheticData(spark: SparkSession): Unit = { import spark.implicits._ // Create data directory new File("data").mkdirs() // Generate taxi dataset val taxiData = (1 to 100000).map { i => val hour = scala.util.Random.nextInt(24).toString + ".0" val fareAmount = 5.0 + scala.util.Random.nextDouble() * 50.0 val year = 2020 + scala.util.Random.nextInt(4) (i, hour, fareAmount, year) }.toDF("trip_id", "hour", "fare_amount", "year") taxiData.coalesce(1) .write .mode("overwrite") .option("header", "true") .csv("data/taxi_small.csv") // Generate housing dataset val housingData = (1 to 50000).map { i => val rooms = 1 + scala.util.Random.nextInt(8) val age = scala.util.Random.nextInt(50) val distance = 1.0 + scala.util.Random.nextDouble() * 10.0 val crime = scala.util.Random.nextDouble() * 20.0 val medHValue = 100000 + rooms * 50000 + scala.util.Random.nextGaussian() * 20000 (rooms, age, distance, crime, medHValue) }.toDF("rooms", "age", "distance", "crime", "medhvalue") housingData.coalesce(1) .write .mode("overwrite") .option("header", "true") .csv("data/housing.csv") println("Synthetic datasets generated") } def runTaxiAnalysis(spark: SparkSession): Unit = { import spark.implicits._ // STEP 3: Define Schema & Load Taxi Dataset val schema = StructType(Array( StructField("trip_id", IntegerType, true), StructField("hour", StringType, true), StructField("fare_amount", DoubleType, true), StructField("year", IntegerType, true) )) val file = "data/taxi_small.csv" val df = spark.read .option("inferSchema", "false") .option("header", true) .schema(schema) .csv(file) df.cache() println("Taxi dataset loaded and cached") // STEP 4: Perform Simple Aggregations println("=== Hourly Trip Counts ===") df.groupBy("hour").count().orderBy("hour").show(4) // STEP 5: Filter and Select Narrow Subset println("=== Midnight Trips (hour = 0) ===") df.select($"hour", $"fare_amount") .filter($"hour" === "0.0") .show(2) // STEP 6: Explain Query Plan println("=== Query Plan ===") df.explain("formatted") // STEP 7: Save Data with Partitioning df.write .mode("overwrite") .format("parquet") .partitionBy("year") .option("path", "data/partitioned_taxi") .saveAsTable("taxi") println("Taxi analysis completed") } def runHousingMLPipeline(spark: SparkSession): Unit = { import spark.implicits._ // Load housing data val housingDF = spark.read .option("header", "true") .option("inferSchema", "true") .csv("data/housing.csv") val featureCols = Array("rooms", "age", "distance", "crime") val labelName = "medhvalue" // Split data val Array(trainData, testData) = housingDF.randomSplit(Array(0.8, 0.2), seed = 42) // STEP 8: Build ML Pipeline val assembler = new VectorAssembler() .setInputCols(featureCols) .setOutputCol("rawfeatures") val scaler = new StandardScaler() .setInputCol("rawfeatures") .setOutputCol("features") .setWithStd(true) .setWithMean(true) val rf = new RandomForestRegressor() .setLabelCol(labelName) .setFeaturesCol("features") .setNumTrees(100) val pipeline = new Pipeline().setStages(Array(assembler, scaler, rf)) // Train model val pipelineModel = pipeline.fit(trainData) val predictions = pipelineModel.transform(testData) // STEP 9: Evaluate ML Model val evaluator = new RegressionEvaluator() .setLabelCol(labelName) .setMetricName("rmse") val rmse = evaluator.evaluate(predictions) println(f"Random Forest RMSE: $rmse%.2f") // STEP 10: GPU-accelerated XGBoost val xgbParamFinal = Map( "tree_method" -> "gpu_hist", "num_workers" -> 1, "max_depth" -> 6, "eta" -> 0.1, "subsample" -> 0.8, "colsample_bytree" -> 0.8 ) val xgbRegressor = new XGBoostRegressor(xgbParamFinal) .setLabelCol(labelName) .setFeaturesCol("features") .setNumRound(100) val xgbPipeline = new Pipeline().setStages(Array(assembler, scaler, xgbRegressor)) val xgbModel = xgbPipeline.fit(trainData) val xgbPredictions = xgbModel.transform(testData) val xgbRmse = evaluator.evaluate(xgbPredictions) println(f"XGBoost GPU RMSE: $xgbRmse%.2f") // STEP 12: Save Models new File("models").mkdirs() pipelineModel.write.overwrite().save("models/rf_model") xgbModel.write.overwrite().save("models/xgb_model") println("ML pipeline completed and models saved") }
}